import{bV as s,aL as a,u as i,G as l}from"./chunks/framework.BfzMay2U.js";const u=JSON.parse('{"title":"Go主机安全面试：Linux提权与持久化检测","description":"","frontmatter":{"title":"Go主机安全面试：Linux提权与持久化检测","date":"2026-07-04T17:03:35.000Z","categories":["Interview"],"tags":["go","interview","security","hids","edr","linux"]},"headers":[],"relativePath":"interview/go-hids-linux-privilege-persistence.md","filePath":"interview/go-hids-linux-privilege-persistence.md"}'),n={name:"interview/go-hids-linux-privilege-persistence.md"};function t(d,e,o,p,r,c){return a(),i("div",null,[...e[0]||(e[0]=[l(`<h1 id="go-主机安全面试-linux-提权与持久化检测" tabindex="-1">Go 主机安全面试：Linux 提权与持久化检测 <a class="header-anchor" href="#go-主机安全面试-linux-提权与持久化检测" aria-label="Permalink to &quot;Go 主机安全面试：Linux 提权与持久化检测&quot;">​</a></h1><p>Linux 主机安全面试常把“攻击者拿到低权限 shell 之后会做什么”作为主线。Go 研发要能把提权、权限变更、持久化落点和告警降噪讲清楚，而不是只背几个漏洞名。</p><h2 id="岗位场景" tabindex="-1">岗位场景 <a class="header-anchor" href="#岗位场景" aria-label="Permalink to &quot;岗位场景&quot;">​</a></h2><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Web RCE / 弱口令登录</span></span>
<span class="line"><span>  -&gt; 低权限 shell</span></span>
<span class="line"><span>  -&gt; 提权探测：sudo、SUID、内核漏洞、敏感配置</span></span>
<span class="line"><span>  -&gt; 持久化：cron、systemd、SSH key、动态库劫持</span></span>
<span class="line"><span>  -&gt; 横向移动 / 数据窃取</span></span>
<span class="line"><span>  -&gt; HIDS/EDR 采集、关联、告警、留证</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这类检测的关键是把“权限发生变化”和“攻击者留下入口”连起来看。</p><h2 id="高频面试题" tabindex="-1">高频面试题 <a class="header-anchor" href="#高频面试题" aria-label="Permalink to &quot;高频面试题&quot;">​</a></h2><h2 id="_1-linux-提权检测应该重点看哪些行为" tabindex="-1">1. Linux 提权检测应该重点看哪些行为？ <a class="header-anchor" href="#_1-linux-提权检测应该重点看哪些行为" aria-label="Permalink to &quot;1. Linux 提权检测应该重点看哪些行为？&quot;">​</a></h2><blockquote><p>简答：重点看身份变化、权限边界突破和敏感配置改动。</p></blockquote><p>常见信号：</p><ul><li>普通用户执行 <code>sudo</code>、<code>su</code>、<code>pkexec</code>、<code>newgrp</code>。</li><li>新增 SUID/SGID 文件，尤其落在 <code>/tmp</code>、<code>/var/tmp</code>、Web 目录。</li><li>修改 <code>/etc/passwd</code>、<code>/etc/shadow</code>、<code>/etc/sudoers</code>。</li><li>加载异常内核模块或执行本地提权 POC。</li><li>Web 服务用户启动 shell 后执行权限探测命令。</li></ul><p>Go 落地思路：</p><ul><li>进程事件保留 <code>uid</code>、<code>euid</code>、<code>gid</code>、<code>egid</code>、父进程和命令行。</li><li>文件事件关注权限位、属主、路径和哈希变化。</li><li>告警要带证据：哪个用户、哪个进程、改了哪个文件、权限从什么变成什么。</li></ul><h2 id="_2-suid-文件为什么是高频提权风险" tabindex="-1">2. SUID 文件为什么是高频提权风险？ <a class="header-anchor" href="#_2-suid-文件为什么是高频提权风险" aria-label="Permalink to &quot;2. SUID 文件为什么是高频提权风险？&quot;">​</a></h2><blockquote><p>简答：SUID 程序会以文件属主权限运行，错误配置可能让普通用户拿到 root 能力。</p></blockquote><p>关键知识点：</p><ul><li>SUID 位常见权限是 <code>-rwsr-xr-x</code>。</li><li>合法 SUID 程序包括 <code>passwd</code>、<code>sudo</code>、<code>su</code>。</li><li>攻击者可能复制 shell 并设置 SUID，或利用可写路径里的异常二进制。</li></ul><p>Go 落地思路：</p><div class="language-go vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">func</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> HasSUID</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">mode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> uint32</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">	return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> mode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">04000</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> !=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ul><li>文件采集层只判断权限变化，不在采集层写复杂策略。</li><li>检测层组合路径、属主、创建进程和时间窗口。</li><li>白名单要精确到路径和哈希，不能只按文件名放行。</li></ul><h2 id="_3-cron-和-systemd-持久化怎么检测" tabindex="-1">3. cron 和 systemd 持久化怎么检测？ <a class="header-anchor" href="#_3-cron-和-systemd-持久化怎么检测" aria-label="Permalink to &quot;3. cron 和 systemd 持久化怎么检测？&quot;">​</a></h2><blockquote><p>简答：看计划任务和服务单元是否新增、被篡改，以及它们启动的命令是否可疑。</p></blockquote><p>重点路径：</p><table tabindex="0"><thead><tr><th>类型</th><th>关注位置</th></tr></thead><tbody><tr><td>用户 cron</td><td><code>/var/spool/cron/</code>、<code>/var/spool/cron/crontabs/</code></td></tr><tr><td>系统 cron</td><td><code>/etc/crontab</code>、<code>/etc/cron.*</code></td></tr><tr><td>systemd</td><td><code>/etc/systemd/system/</code>、<code>/usr/lib/systemd/system/</code></td></tr><tr><td>自启动脚本</td><td><code>/etc/rc.local</code>、用户 profile 文件</td></tr></tbody></table><p>Go 落地思路：</p><ul><li>监听文件创建、写入、重命名和权限变化。</li><li>解析关键字段：执行用户、命令、定时表达式、<code>ExecStart</code>。</li><li>新增服务后如果紧跟 <code>systemctl enable/start</code>，风险更高。</li></ul><h2 id="_4-ssh-key-持久化如何判断误报" tabindex="-1">4. SSH key 持久化如何判断误报？ <a class="header-anchor" href="#_4-ssh-key-持久化如何判断误报" aria-label="Permalink to &quot;4. SSH key 持久化如何判断误报？&quot;">​</a></h2><blockquote><p>简答：不能看到 <code>authorized_keys</code> 变化就直接高危，要结合操作者、来源进程和主机基线。</p></blockquote><p>风险信号：</p><ul><li>Web 用户或业务进程写入 <code>~/.ssh/authorized_keys</code>。</li><li>非交互时段批量修改多个用户的 SSH key。</li><li>新 key 写入后很快出现外部登录成功。</li><li>key 注释、来源 IP、文件属主与历史基线不一致。</li></ul><p>Go 落地思路：</p><ul><li>文件事件记录 <code>path</code>、<code>uid</code>、<code>process.name</code>、<code>process.cmdline</code>。</li><li>登录事件记录用户、来源 IP、认证方式和时间。</li><li>用短窗口关联“key 写入 -&gt; SSH 登录”，比单点文件告警更可靠。</li></ul><h2 id="_5-为什么提权检测不能只靠命令行关键字" tabindex="-1">5. 为什么提权检测不能只靠命令行关键字？ <a class="header-anchor" href="#_5-为什么提权检测不能只靠命令行关键字" aria-label="Permalink to &quot;5. 为什么提权检测不能只靠命令行关键字？&quot;">​</a></h2><blockquote><p>简答：关键字适合粗筛，但攻击者可以改名、编码、间接执行，单点匹配容易漏报和误报。</p></blockquote><p>例子：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>chmod u+s /tmp/sh</span></span>
<span class="line"><span>cp /bin/bash /tmp/.x &amp;&amp; chmod 4755 /tmp/.x</span></span>
<span class="line"><span>echo &#39;user ALL=(ALL) NOPASSWD:ALL&#39; &gt;&gt; /etc/sudoers</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>关键知识点：</p><ul><li>命令行可能缺失、截断或被混淆。</li><li>文件权限变化比命令文本更接近结果证据。</li><li>进程父子关系能解释行为来源。</li></ul><p>Go 落地思路：</p><ul><li>命令行命中作为候选事件。</li><li>文件最终状态作为强证据。</li><li>规则输出 <code>reason</code>，说明命中了哪些字段，方便客户复核。</li></ul><h2 id="_6-如何设计一条-web-用户提权尝试-规则" tabindex="-1">6. 如何设计一条“Web 用户提权尝试”规则？ <a class="header-anchor" href="#_6-如何设计一条-web-用户提权尝试-规则" aria-label="Permalink to &quot;6. 如何设计一条“Web 用户提权尝试”规则？&quot;">​</a></h2><blockquote><p>简答：用 Web 父进程、低权限用户、提权命令和敏感文件变化做组合。</p></blockquote><p>简化规则：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>父进程属于 nginx/php-fpm/tomcat</span></span>
<span class="line"><span>  + 执行用户是 www-data/nginx/apache</span></span>
<span class="line"><span>  + 命令包含 sudo/su/chmod 4755/sudoers</span></span>
<span class="line"><span>  或敏感文件权限发生变化</span></span>
<span class="line"><span>  =&gt; Web RCE 后提权尝试</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Go 落地思路：</p><div class="language-go vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">type</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Finding</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	Severity </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">	Reason   []</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ul><li>不要只返回 <code>bool</code>，否则告警解释性差。</li><li>先做少量稳定规则，覆盖高价值场景。</li><li>服务端再做跨事件攻击链还原，Agent 侧避免重规则拖垮性能。</li></ul><h2 id="_7-linux-下有哪些采集来源可以支持这类检测" tabindex="-1">7. Linux 下有哪些采集来源可以支持这类检测？ <a class="header-anchor" href="#_7-linux-下有哪些采集来源可以支持这类检测" aria-label="Permalink to &quot;7. Linux 下有哪些采集来源可以支持这类检测？&quot;">​</a></h2><blockquote><p>简答：进程、文件、登录和权限变化都要采，单一来源不够。</p></blockquote><table tabindex="0"><thead><tr><th>来源</th><th>适合采集</th><th>主要风险</th></tr></thead><tbody><tr><td>auditd</td><td>exec、文件写入、权限修改</td><td>规则配置和性能成本</td></tr><tr><td>eBPF</td><td>execve、chmod、chown、open、rename</td><td>内核兼容和丢事件处理</td></tr><tr><td>procfs</td><td>补充进程上下文</td><td>短进程容易错过</td></tr><tr><td>auth log</td><td>SSH、sudo、su 登录审计</td><td>发行版路径和格式差异</td></tr></tbody></table><p>Go 落地思路：</p><ul><li>多来源事件统一成标准字段，例如 <code>process.*</code>、<code>file.*</code>、<code>user.*</code>。</li><li>采集失败和降级状态要上报，避免服务端误以为主机安全。</li><li>高风险事件优先级高于普通文件扫描。</li></ul><h2 id="_8-agent-如何降低这类规则的误报" tabindex="-1">8. Agent 如何降低这类规则的误报？ <a class="header-anchor" href="#_8-agent-如何降低这类规则的误报" aria-label="Permalink to &quot;8. Agent 如何降低这类规则的误报？&quot;">​</a></h2><blockquote><p>简答：用基线、白名单、时间窗口和证据聚合，而不是把规则写成一大坨条件。</p></blockquote><p>常见误报：</p><ul><li>运维正常新增 systemd 服务。</li><li>发布脚本更新 cron。</li><li>安全加固工具修改 sudoers。</li><li>管理员轮换 SSH key。</li></ul><p>Go 落地思路：</p><ul><li>去重 key 可以用 <code>host_id + rule_id + user + path + process_hash</code>。</li><li>白名单要记录命中原因和范围。</li><li>规则分级：单点敏感修改是中危，Web 进程链路加敏感修改才是高危。</li><li>保留原始事件，降噪只影响告警，不影响事后取证。</li></ul><h2 id="学习要点" tabindex="-1">学习要点 <a class="header-anchor" href="#学习要点" aria-label="Permalink to &quot;学习要点&quot;">​</a></h2><ul><li>Linux 权限模型：UID/EUID、SUID/SGID、文件权限位。</li><li>持久化入口：cron、systemd、SSH key、profile、动态库加载。</li><li>Go 工程化：事件结构体、短窗口缓存、队列限流、告警解释字段。</li><li>检测思路：结果证据优先，命令关键字只做辅助。</li></ul><h2 id="小练习" tabindex="-1">小练习 <a class="header-anchor" href="#小练习" aria-label="Permalink to &quot;小练习&quot;">​</a></h2><ol><li>设计一个 <code>FileEvent</code> 结构体，能表达 SUID 位新增、属主变化和写入进程。</li><li>写一条规则：Web 用户在 <code>/tmp</code> 下创建 SUID root 文件时告警。</li><li>思考：如果 <code>authorized_keys</code> 被正常运维系统更新，规则如何降噪？</li><li>复盘一次真实告警时，至少保留进程、文件、用户、时间和原始事件五类证据。</li></ol>`,61)])])}const b=s(n,[["render",t]]);export{u as __pageData,b as default};
